func (db *ClusterAppDB) UpsertPostmeta(appID string, postID int, metaKey, metaValue string) error {
	// get postmeta
	postmetas, err := db.GetPostmetas(appID, []int{postID}, []string{metaKey})
	if err != nil && !errors.Is(err, gorm.ErrRecordNotFound) {
		return err
	}
	if len(postmetas) > 0 {
		return db.UpdatePostmetas(appID, postID, metaKey, metaValue, postmetas)
	} else {
		return db.InsertPostmeta(appID, postID, metaKey, metaValue)
	}

